#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long Z, Y, A, B, C; // use long long to be safe
        scanf("%lld %lld %lld %lld %lld", &Z, &Y, &A, &B, &C);
        long long remaining = Z - Y;
        long long total = A + B + C;
        if(total <= remaining) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

